using UnityEngine;public class ExternalRoadViewController : MonoBehaviour{    [Header("Input")]    public UdpUiRenderReceiver receiver;    [Header("Zone / Lane")]    public Renderer roadLaneRenderer;    public Renderer flowStripRenderer;    [Header("Vehicle Motion")]    public Transform vehicleMarker;    public float markerXMin = -5.0f;    public float markerXMax = 5.0f;    [Header("Emergency Lights")]    public Renderer emergencyLeftRenderer;    public Renderer emergencyRightRenderer;    private Material _laneMaterial;    private Material _flowMaterial;    private Material _leftLightMaterial;    private Material _rightLightMaterial;    private void Start()    {        if (receiver == null)        {            Debug.LogWarning("[ExternalRoadViewController] receiver is not assigned.");            return;        }        if (roadLaneRenderer != null) _laneMaterial = roadLaneRenderer.material;        if (flowStripRenderer != null) _flowMaterial = flowStripRenderer.material;        if (emergencyLeftRenderer != null) _leftLightMaterial = emergencyLeftRenderer.material;        if (emergencyRightRenderer != null) _rightLightMaterial = emergencyRightRenderer.material;        receiver.PacketUpdated += OnPacketUpdated;    }    private void OnDestroy()    {        if (receiver != null)        {            receiver.PacketUpdated -= OnPacketUpdated;        }    }    private void OnPacketUpdated(UiRenderPacket packet)    {        UiRenderState s = packet.uiRender;        if (s == null)        {            return;        }        ApplyZone(s);        ApplyVehicle(s);        ApplyFlow(s);        ApplyEmergency(s);    }    private void ApplyZone(UiRenderState s)    {        if (_laneMaterial == null)        {            return;        }        _laneMaterial.color = UiRenderVisualMap.ZoneColor(s.roadZoneColorCode);    }    private void ApplyVehicle(UiRenderState s)    {        if (vehicleMarker == null)        {            return;        }        float t = Mathf.Clamp01(s.vehicleObjectPos / 100f);        float x = Mathf.Lerp(markerXMin, markerXMax, t);        Vector3 p = vehicleMarker.localPosition;        vehicleMarker.localPosition = new Vector3(x, p.y, p.z);    }    private void ApplyFlow(UiRenderState s)    {        if (_flowMaterial == null)        {            return;        }        float phase = Mathf.Clamp(s.icFlowPhase, 0, 7) / 8f;        float dir = 0f;        if (s.roadFlowDirection == 1) dir = phase;        if (s.roadFlowDirection == 2) dir = -phase;        // Presentation-only animation shift.        _flowMaterial.mainTextureOffset = new Vector2(dir, 0f);    }    private void ApplyEmergency(UiRenderState s)    {        if (_leftLightMaterial == null || _rightLightMaterial == null)        {            return;        }        UiRenderVisualMap.EmergencyBlink(            s.activeAlertType,            s.emsBlinkPhase,            out Color leftColor,            out Color rightColor        );        _leftLightMaterial.color = leftColor;        _rightLightMaterial.color = rightColor;    }}